import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";


const FAQS = [
  { q: "What is the formula for speed?", a: "Speed = Distance  x  Time. Rearranging: Distance = Speed  x  Time, and Time = Distance  x  Speed. These three relationships are sometimes called the 'magic triangle' of physics. If you travel 180 miles in 3 hours, your average speed is 60 mph. This is average speed - actual speed varies throughout the trip." },
  { q: "How do I convert mph to km/h?", a: "Multiply mph by 1.60934 to get km/h. Divide km/h by 1.60934 to get mph. Quick mental conversion: multiply mph by 1.6. Examples: 60 mph = 96.56 km/h, 100 km/h = 62.14 mph, 30 mph = 48.28 km/h. Most speed limits in Europe use km/h; US and UK use mph." },
  { q: "What is the speed of sound?", a: "The speed of sound in dry air at 20- (68- is approximately 343 m/s (767 mph, 1,235 km/h). This varies with temperature: faster in warmer air, slower in colder air. In water, sound travels ~1,480 m/s - about 4 x  faster than in air. Mach 1 is the speed of sound at the given altitude and conditions." },
  { q: "What is the speed of light?", a: "The speed of light in a vacuum is exactly 299,792,458 m/s (approximately 186,282 miles per second, or about 671 million mph). This is designated 'c' and is the universal speed limit - no object with mass can reach or exceed it. Light from the Sun takes about 8 minutes to reach Earth." },
  { q: "How do I calculate average speed for a trip with multiple legs?", a: "Do NOT simply average the speeds. Correct method: Total Distance  x  Total Time. Example: Drive 100 miles at 50 mph (takes 2 hours), then 100 miles at 100 mph (takes 1 hour). Total = 200 miles in 3 hours = 66.7 mph average - not 75 mph. Averaging speeds only works when time is equal for each leg." },
  { q: "What is the difference between speed and velocity?", a: "Speed is a scalar - it only has magnitude (how fast). Velocity is a vector - it has both magnitude and direction (how fast AND which way). A car going 60 mph north and a car going 60 mph south have the same speed but opposite velocities. Speed is always positive; velocity can be negative (opposite direction)." },
  { q: "How fast is 100 km/h in mph?", a: "100 km/h = 62.14 mph. This is approximately 60 mph - the most common highway speed limit in the US. Quick reference: 50 km/h - 31 mph (urban limit), 80 km/h - 50 mph, 100 km/h - 62 mph, 110 km/h - 68 mph, 130 km/h - 81 mph (European motorway)." },
  { q: "What are knots and how are they used?", a: "A knot is one nautical mile per hour. 1 knot = 1.15078 mph = 1.852 km/h. Knots are the standard speed unit in aviation and maritime navigation because nautical miles are based on latitude degrees, making navigation calculations simpler. Weather reports also use knots for wind speed." },
];

const SPEED_CONVERSIONS = [
  ["30 mph", "48.28 km/h", "26.82 m/s", "26.11 knots"],
  ["60 mph", "96.56 km/h", "26.82 m/s", "52.14 knots"],
  ["100 mph", "160.93 km/h", "44.70 m/s", "86.90 knots"],
  ["100 km/h", "62.14 mph", "27.78 m/s", "53.99 knots"],
  ["343 m/s (sound)", "767.27 mph", "1,235 km/h", "666.74 knots"],
  ["Mach 1 (sea level)", "761 mph", "1,225 km/h", "661.5 knots"],
];

type SolveFor = "speed" | "distance" | "time";

export default function SpeedCalculator() {
  const [solveFor, setSolveFor] = useState<SolveFor>("speed");
  const [distance, setDistance] = useState(100);
  const [time, setTime] = useState(2);
  const [speed, setSpeed] = useState(60);

  const result = solveFor === "speed" ? distance / time
    : solveFor === "distance" ? speed * time
    : distance / speed;

  const label = solveFor === "speed" ? "mph" : solveFor === "distance" ? "miles" : "hours";
  const resultLabel = solveFor === "speed" ? "Speed" : solveFor === "distance" ? "Distance" : "Time";

  const mph = solveFor === "speed" ? result : speed;
  const kmh = mph * 1.60934;
  const ms = mph * 0.44704;
  const knots = mph * 0.868976;

  return (
    <>
      <SEOHead
        title="Free Speed Calculator Online - Calculate Speed Distance or Time Instantly | CalcHive"
        description="Free online speed calculator. Calculate speed, distance or time and convert between mph, km/h, m/s and knots instantly. 100% free for everyone, no signup required."
        canonical="/speed-calculator"
        keywords="free speed calculator, speed distance time calculator free online, mph to km/h converter free, calculate speed free, free velocity calculator online"
        category="Science Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-cyan-600 dark:text-cyan-400 bg-cyan-50 dark:bg-cyan-950/50 px-3 py-1 rounded-full mb-4 inline-block">Measurement</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Speed Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free speed calculator to calculate speed free, distance, or time and convert between mph, km/h, m/s, and knots. This speed distance time calculator free online also works as a mph to km/h converter free and free velocity calculator online.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <div className="flex gap-2 mb-6">
          {(["speed", "distance", "time"] as SolveFor[]).map(v => (
            <button key={v} onClick={() => setSolveFor(v)} className={`flex-1 py-2 rounded-xl text-sm font-semibold border capitalize transition-all ${solveFor === v ? "bg-cyan-600 text-white border-cyan-600" : "bg-card text-muted-foreground border-border hover:border-cyan-400"}`}>Solve for {v}</button>
          ))}
        </div>
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="space-y-6 mb-8">
            {solveFor !== "distance" && <SliderInput id="distance" label="Distance (miles)" value={distance} min={1} max={5000} step={1} onChange={setDistance} format={v => `${v} mi`} testId="input-distance" />}
            {solveFor !== "time" && <SliderInput id="time" label="Time (hours)" value={time} min={0.1} max={100} step={0.1} onChange={setTime} format={v => `${v.toFixed(1)} hrs`} testId="input-time" />}
            {solveFor !== "speed" && <SliderInput id="speed" label="Speed (mph)" value={speed} min={1} max={1000} step={1} onChange={setSpeed} format={v => `${v} mph`} testId="input-speed" />}
          </div>
          <motion.div key={`${solveFor}-${result}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-cyan-500 to-cyan-700 rounded-2xl p-6 mb-4 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">{resultLabel}</p>
              <p className="text-5xl font-black text-white tracking-tight" data-testid="result-value">{result.toFixed(2)} {label}</p>
            </div>
            {solveFor === "speed" && (
              <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
                {[{ label: "mph", value: mph.toFixed(2) }, { label: "km/h", value: kmh.toFixed(2) }, { label: "m/s", value: ms.toFixed(2) }, { label: "Knots", value: knots.toFixed(2) }].map(({ label: l, value }) => (
                  <div key={l} className="bg-accent/60 border border-border rounded-xl p-3 text-center">
                    <p className="text-xs text-muted-foreground font-medium mb-1">{l}</p>
                    <p className="text-base font-extrabold text-foreground">{value}</p>
                  </div>
                ))}
              </div>
            )}
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Speed Distance and Time for Free</h2>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>Speed = Distance  x  Time</p>
            <p>Distance = Speed  x  Time</p>
            <p>Time = Distance  x  Speed</p>
            <p className="text-xs text-muted-foreground mt-2">Unit conversions: 1 mph = 1.60934 km/h = 0.44704 m/s = 0.86898 knots</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">How to Convert Between mph km/h m/s and Knots</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["mph", "km/h", "m/s", "knots"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {SPEED_CONVERSIONS.map(([mph_, kmh_, ms_, kn]) => (
                  <tr key={mph_} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-bold text-cyan-600 dark:text-cyan-400">{mph_}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{kmh_}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{ms_}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{kn}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <h2 className="text-2xl font-bold text-foreground">Free Physics Speed Tool for Students and Everyone</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Speed", "30 min", "1 hour", "2 hours", "5 hours"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[30, 45, 60, 75, 100, 120].map(spd => (
                  <tr key={spd} className={`hover:bg-muted/30 ${spd === Math.round(solveFor !== "speed" ? speed : result) ? "bg-cyan-50 dark:bg-cyan-950/20 font-semibold" : ""}`}>
                    <td className="py-2.5 px-4 font-bold text-cyan-600 dark:text-cyan-400">{spd} mph</td>
                    {[0.5, 1, 2, 5].map(h => <td key={h} className="py-2.5 px-4 text-muted-foreground">{(spd * h).toFixed(0)} mi</td>)}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/speed-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


